function solve(n, edges, label) {
    const graph = new Map();
    for (let i = 0; i < n; i++) {
        graph.set(i, []);
    }
    for (const [u, v] of edges) {
        graph.get(u).push(v);
        graph.get(v).push(u);
    }

    const memo = new Map();
    const visited = new Array(n).fill(false);

    function dfs(node, visited, path) {
        const key = node + ',' + visited.join(',');
        if (memo.has(key)) {
            return memo.get(key);
        }

        const currentChar = label[node];
        const newPath = path + currentChar;

        let maxPalindrome = 1;
        const neighbors = graph.get(node);
        for (const neighbor of neighbors) {
            if (!visited[neighbor]) {
                visited[neighbor] = true;
                const result = dfs(neighbor, visited, newPath);
                maxPalindrome = Math.max(maxPalindrome, result);
                visited[neighbor] = false;
            }
        }

        memo.set(key, maxPalindrome);
        return maxPalindrome;
    }

    let maxLength = 0;
    for (let i = 0; i < n; i++) {
        visited[i] = true;
        const result = dfs(i, visited, label[i]);
        maxLength = Math.max(maxLength, result);
        visited[i] = false;
    }

    return maxLength;
}

